import React from "react";
import "./ContractPage.css";
import { useNavigate } from "react-router-dom";
import { useAppContext } from "../../context/AppContext";

export const ContractPage: React.FC = () => {
  const navigate = useNavigate();
  const { distribution, incomeTypes, setContractConfirmed } = useAppContext();
  const { coOwners, projectName, type } = distribution;

  const today = new Date().toLocaleDateString("uk-UA", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  });

  const companyLabel = type === "company" ? "Компанія" : "Проєкт";
  const companyShort = `«${projectName}»`;

  const getShare = (rules: { ownerId: number; share: string }[], ownerId: number) => {
    const r = rules.find((r) => r.ownerId === ownerId);
    return r ? `${r.share}%` : "—";
  };

  return (
    <div className="contract-wrapper">
      <h1 className="contract-main-title">Договір про співпрацю</h1>

      <div className="contract-body">
        {/* Doc header */}
        <p className="contract-doc-title">
          ДОГОВІР ПРО СПІВВЛАСНІСТЬ ТА{"\n"}РОЗПОДІЛ ДОХОДІВ
        </p>

        <p className="contract-text">
          Цей Договір про співвласність та розподіл доходів (надалі – «Договір»)
          укладений [●] («Дата набрання чинності») між:
        </p>

        {coOwners.map((o, i) => (
          <p className="contract-owner-line" key={o.id}>
            {i + 1}. {o.name} («Співвласник {i + 1}»)
          </p>
        ))}

        <p className="contract-text" style={{ marginTop: 8 }}>
          (разом – «Сторони», а окремо – «Сторона»).
        </p>

        <p className="contract-text">Сторони домовились про таке:</p>

        {/* Section 1 */}
        <p className="contract-section-title">1. {companyLabel.toUpperCase()}</p>

        <p className="contract-subsection">
          1.1. Сторони с співвласниками {type === "company" ? "компанії" : "проєкту"}{" "}
          {companyShort} (надалі – {companyShort}).
        </p>
        <p className="contract-subsection">
          1.2. Частки у власності на {companyLabel} {companyShort} розподіляються порівну:
        </p>

        {coOwners.map((o, i) => (
          <p className="contract-owner-line" key={o.id}>
            Співвласник {i + 1}: {o.share}%
          </p>
        ))}

        {/* Section 2 */}
        <p className="contract-section-title">2. РОЗПОДІЛ ДОХОДІВ</p>

        <p className="contract-subsection">
          Сторони домовляються про такий розподіл доходів та прибутків від діяльності{" "}
          {companyLabel} {companyShort} та її проєктів:
        </p>

        {/* 2.1 Project */}
        {incomeTypes.project.length > 0 && (
          <>
            <p className="contract-subsection">
              2.1. Дохід від проєкту {companyShort}
            </p>
            {coOwners.map((o, i) => (
              <p className="contract-owner-line" key={o.id}>
                Співвласник {i + 1}: {getShare(incomeTypes.project, o.id)}
              </p>
            ))}
          </>
        )}

        {/* 2.2 Clients */}
        {incomeTypes.clients.length > 0 && (
          <>
            <p className="contract-subsection">
              2.2. Дохід від перших 30 клієнтів {companyLabel}
            </p>
            {coOwners.map((o, i) => (
              <p className="contract-owner-line" key={o.id}>
                Співвласник {i + 1}: {getShare(incomeTypes.clients, o.id)}
              </p>
            ))}
          </>
        )}

        {/* 2.3 Profit */}
        {incomeTypes.profit.length > 0 && (
          <>
            <p className="contract-subsection">
              2.3. Чистий прибуток {companyLabel}
            </p>
            {coOwners.map((o, i) => (
              <p className="contract-owner-line" key={o.id}>
                Співвласник {i + 1}: {getShare(incomeTypes.profit, o.id)}
              </p>
            ))}
          </>
        )}

        {/* Section 3 */}
        <p className="contract-section-title">3. ПРАВА ТА ОБОВʼЯЗКИ</p>
        <p className="contract-subsection">
          3.1. Кожна Сторона зобовʼязується діяти сумлінно та в найкращих інтересах{" "}
          {companyLabel} {companyShort}.
        </p>
        <p className="contract-subsection">
          3.2. Сторони мають рівні права щодо прийняття рішень стосовно управління,
          операцій та стратегії {companyLabel}.
        </p>
        <p className="contract-subsection">
          3.3. Жодна зі Сторін не може брати на себе зобовʼязання від імені{" "}
          {companyLabel}, що перевищують [●], без попередньої письмової згоди іншої Сторони.
        </p>

        {/* Section 4 */}
        <p className="contract-section-title">4. СТРОК ДІЇ ТА ПРИПИНЕННЯ</p>
        <p className="contract-subsection">
          4.1. Цей Договір діє до моменту його припинення за взаємною письмовою згодою Сторін.
        </p>
        <p className="contract-subsection">
          4.2. У разі припинення Договору Сторони проводять остаточні розрахунки та
          розподіляють усі наявні прибутки чи збитки відповідно до встановлених часток.
        </p>

        {/* Section 5 */}
        <p className="contract-section-title">5. ЗАСТОСОВНЕ ПРАВО ТА ЮРИСДИКЦІЯ</p>
        <p className="contract-subsection">
          5.1. Цей Договір регулюється та тлумачиться відповідно до законодавства Англії та Уельсу.
        </p>
        <p className="contract-subsection">
          5.2. Усі спори, що виникають із цього Договору або у звʼязку з ним, підлягають
          виключній юрисдикції судів Англії та Уельсу.
        </p>

        {/* Section 6 */}
        <p className="contract-section-title">6. ПОВНОТА ДОГОВОРУ</p>
        <p className="contract-subsection">
          Цей Договір становить повне розуміння між Сторонами щодо його предмета та замінює
          собою всі попередні домовленості, угоди чи представлення.
        </p>

        {/* Section 7 — Signatures */}
        <p className="contract-section-title">7. ПІДПИСИ</p>

        <div className="contract-signatures">
          {coOwners.map((o, i) => (
            <div className="contract-signature-block" key={o.id}>
              <span className="contract-signature-role">Підпис Співвласника {i + 1}:</span>
              <span className="contract-signature-name">Імʼя: {o.name}</span>
            </div>
          ))}
          <p className="contract-date-line">Дата: ___________</p>
        </div>

        {/* Sign box */}
        <p className="contract-sign-label">Підпис</p>
        <div className="contract-sign-box" />
      </div>

      {/* Fixed footer */}
      <div className="contract-footer">
        <button
          className="contract-confirm-btn"
          onClick={() => { setContractConfirmed(true); navigate("/summary"); }}
        >
          Підтвердити
        </button>
      </div>
    </div>
  );
};
